import {proxy, unproxy } from "./network/hijack"
import {getI18n} from "@spotter/i18n-sdk";
import { startSubAcp } from "./app/app-communication-protocol";
import { registerApps } from "./app/appRegistry";
import { addErrorHandler, removeErrorHandler, removeGlobalUncaughtErrorHandler } from "qiankun";
import { addGlobalUncaughtErrorHandler } from "qiankun";
import {SpotterRouter} from "../router";
import {Logger} from "./logger";

export interface SpotterMainApp{
    network: {
        /**
         * 取消全局的网络劫持
         */
        unproxy: typeof unproxy,
        /**
         * 启用全局的网络劫持
         */
        proxy: typeof proxy
    }
    log: {
        logger: Logger
    }
    i18n: ReturnType<typeof getI18n>
    microApp: {
        startSubAcp: typeof startSubAcp,
        registerApps: typeof registerApps
        addGlobalUncaughtErrorHandler: typeof addGlobalUncaughtErrorHandler,
        addErrorHandler: typeof addErrorHandler,
        removeErrorHandler?: typeof removeErrorHandler,
        removeGlobalUncaughtErrorHandler?: typeof removeGlobalUncaughtErrorHandler
    }
    router: SpotterRouter
}
